// src/contexts/AuthContext.js
import { createContext } from 'react';

// Create the auth context with default values
const AuthContext = createContext({
  user: null,
  loading: false,
  error: null,
  isAuthenticated: false,
  login: () => {},
  register: () => {},
  logout: () => {},
  updateProfile: () => {},
  refreshUser: () => {}
});

export default AuthContext;
